import { forwardRef } from "react";
import type { HTMLAttributes, ReactElement } from "react";
import { Slot } from "@radix-ui/react-slot";
import { clsx } from "clsx";
import * as styles from "./ToggleTile.css";
import type { ToggleTileSize } from "./ToggleTile.config";
import { DEFAULT_TOGGLE_TILE_SIZE } from "./ToggleTile.config";

interface ToggleTileCustomProps {
  /**
   * The size of the tile, which controls the padding.
   * @default 'lg'
   */
  size?: ToggleTileSize;

  /**
   * Whether the tile is in a checked/selected state.
   * Controls the visual styling for the checked state.
   * @default false
   */
  checked?: boolean;

  /**
   * Whether the tile is disabled.
   * Controls cursor and opacity styling.
   * @default false
   */
  disabled?: boolean;

  /**
   * Whether the tile is in an invalid/error state.
   * Controls the error border styling (only visible when not checked).
   * @default false
   */
  invalid?: boolean;

  /**
   * The child element to render. ToggleTile merges its styles onto this element.
   * The child should be an interactive element like `<label>` or `<button>`.
   */
  children: ReactElement;
}

export interface ToggleTileProps
  extends
    Omit<HTMLAttributes<HTMLElement>, keyof ToggleTileCustomProps>,
    ToggleTileCustomProps {}

/**
 * A style-only tile component for toggle inputs (checkbox, radio).
 *
 * **How it works:** ToggleTile renders its child element directly, merging
 * tile styles onto it. Whatever element you pass as a child is what gets
 * rendered in the DOM — ToggleTile itself adds no wrapper element.
 *
 * **⚠️ No accessibility built-in.** This component only provides visual styling.
 * You must ensure:
 * - The child is a semantically appropriate element (e.g., `<label>`, `<button>`)
 * - Proper ARIA attributes are set on inputs
 * - Focus states are handled correctly
 *
 * For most use cases, prefer `CheckboxTile` or `RadioButtonTile` which handle
 * accessibility automatically. Use `ToggleTile` only for custom layouts where
 * you manage accessibility yourself.
 *
 * @example
 * <ToggleTile checked={isChecked} disabled={isDisabled}>
 *   <label>
 *     <input type="checkbox" />
 *     Option 1
 *   </label>
 * </ToggleTile>
 */
export const ToggleTile = forwardRef<HTMLElement, ToggleTileProps>(
  (
    {
      size = DEFAULT_TOGGLE_TILE_SIZE,
      checked = false,
      disabled = false,
      invalid = false,
      className,
      children,
      ...props
    },
    ref
  ) => {
    return (
      <Slot
        ref={ref}
        className={clsx(styles.toggleTile({ size }), className)}
        data-checked={checked || undefined}
        data-disabled={disabled || undefined}
        data-invalid={invalid || undefined}
        {...props}
      >
        {children}
      </Slot>
    );
  }
);

ToggleTile.displayName = "ToggleTile";
